// SPDX-License-Identifier: MIT
pragma solidity ^0.8.34;

import {SafeTransferLib} from "solady/utils/SafeTransferLib.sol";
import {BaseDistributor} from "./BaseDistributor.sol";
import {IHook} from "../hook/IHook.sol";
import {FixedPointMathLib} from "solady/utils/FixedPointMathLib.sol";

//   ____ _ _
//  / ___| (_) __ _ _   _  ___
// | |   | | |/ _` | | | |/ _ \
// | |___| | | (_| | |_| |  __/
//  \____|_|_|\__, |\__,_|\___|        _               _       __  __  ____
// |  _ \(_)___| |_|_ __(_) |__  _   _| |_ ___  _ __  / |     |  \/  |/ ___|
// | | | | / __| __| '__| | '_ \| | | | __/ _ \| '__| | |_____| |\/| | |
// | |_| | \__ \ |_| |  | | |_) | |_| | || (_) | |    | |_____| |  | | |___
// |____/|_|___/\__|_|  |_|_.__/ \__,_|\__\___/|_|    |_|     |_|  |_|\____|

struct BatchConfiguration {
    Strategy[] strategies;
    uint256 fallbackHook;
}

struct Strategy {
    uint256 proportion;
    address hook;
}

/// @title Distributor1MC
/// @notice Clique Airdrop contract (Mekle + ECDSA), allows for multiple claims
/// @author Clique (@Clique2046)
/// @author Eillo (@0xEillo)
contract Distributor is BaseDistributor {
    using SafeTransferLib for address;
    using FixedPointMathLib for uint256;

    mapping(bytes32 configurationId => BatchConfiguration) internal batchConfigurations;
    mapping(address hook => uint256 refCount) internal refCounts;
    uint256 public constant HOOK = _ROLE_1;

    error HookDataLengthMismatch();
    error ConsumedAmountMismatch();
    error InvalidStrategies();
    error InsufficientAllocation();
    error ProportionOverflow();

    event HookAdded(bytes32 indexed configurationId);

    constructor(
        address _signer,
        address _token,
        address _projectAdmin,
        address _vault,
        bool _dynamicRecipient,
        bool _isWrappedToken
    ) BaseDistributor(_signer, _projectAdmin, _vault, _token, _dynamicRecipient, _isWrappedToken) {}

    function setHooks(bytes32 _configurationId, Strategy[] memory _strategies, uint256 _fallbackHook)
        external
        onlyRoles(PROJECT_ADMIN)
    {
        Strategy[] memory oldStrategies = batchConfigurations[_configurationId].strategies;

        for (uint256 i = 0; i < oldStrategies.length; i++) {
            uint256 refCount = refCounts[oldStrategies[i].hook];
            if (refCount > 0) {
                refCount = refCount - 1;
                refCounts[oldStrategies[i].hook] = refCount;
            }

            if (refCount == 0) {
                _removeRoles(oldStrategies[i].hook, HOOK);
            }
        }

        for (uint256 i = 0; i < _strategies.length; i++) {
            if (_strategies[i].proportion > 1 ether) {
                revert InvalidStrategies();
            }

            uint256 refCount = refCounts[_strategies[i].hook];
            if (refCount == 0) {
                _setRoles(_strategies[i].hook, HOOK);
            }
            refCounts[_strategies[i].hook] = refCount + 1;
        }

        if (_fallbackHook > _strategies.length) {
            revert InvalidStrategies();
        }

        batchConfigurations[_configurationId].strategies = _strategies;
        batchConfigurations[_configurationId].fallbackHook = _fallbackHook;
        emit HookAdded(_configurationId);
    }

    function hookTransfer(address _recipient, uint256 _amount) external onlyRoles(HOOK) {
        token.safeTransferFrom(vault, _recipient, _amount);
    }

    /// @notice Internal function to execute the claim
    /// @param _vault vault addressconfigurationId
    /// @param _recipient recipient address
    /// @param _root root of the merkle tree
    /// @param _amount amount of tokens to claim
    /// @param _extra extra data to pass to the claim function
    function _execute(address _vault, address _recipient, bytes32 _root, uint256 _amount, bytes memory _extra)
        internal
        override
    {
        bytes[] memory hookData_ = abi.decode(_extra, (bytes[]));
        bytes32 _configurationId = configurationId[_root];
        BatchConfiguration memory _batchConfiguration = batchConfigurations[_configurationId];

        if (_batchConfiguration.strategies.length != hookData_.length) {
            revert HookDataLengthMismatch();
        }

        uint256 totalConsumed = 0;

        for (uint256 i = 0; i < _batchConfiguration.strategies.length; i++) {
            Strategy memory _strategy = _batchConfiguration.strategies[i];
            if (i == _batchConfiguration.fallbackHook) {
                continue;
            }

            uint256 hookAmount = _amount.mulWad(_strategy.proportion);

            uint256 _consumed = IHook(_strategy.hook).execute(_vault, _recipient, _root, hookAmount, hookData_[i]);
            totalConsumed += _consumed;
        }

        if (_batchConfiguration.fallbackHook < _batchConfiguration.strategies.length) {
            if (totalConsumed > _amount) {
                revert InsufficientAllocation();
            }
            uint256 fallbackAmount = _amount - totalConsumed;
            uint256 fallbackConsumed = IHook(_batchConfiguration.strategies[_batchConfiguration.fallbackHook].hook)
                .execute(_vault, _recipient, _root, fallbackAmount, hookData_[_batchConfiguration.fallbackHook]);
            totalConsumed += fallbackConsumed;
        }

        if (totalConsumed != _amount) revert ConsumedAmountMismatch();
    }

    function getBatchConfiguration(bytes32 _configurationId) external view returns (BatchConfiguration memory) {
        return batchConfigurations[_configurationId];
    }

    function getHookAddr(bytes32 _configurationId, uint256 _index) external view returns (address) {
        return batchConfigurations[_configurationId].strategies[_index].hook;
    }
}

