// SPDX-License-Identifier: MIT
pragma solidity ^0.8.34;

import {ECDSA} from "solady/utils/ECDSA.sol";
import {FixedPointMathLib} from "solady/utils/FixedPointMathLib.sol";
import {OwnableRoles} from "solady/auth/OwnableRoles.sol";

struct ClaimInfo {
    uint256 lastClaimedBlock;
    uint256 claimedAmount;
}

struct SingleTierFeeRate {
    // Fee rate denominated in 10^-18.
    uint256 feeRate;
    uint256 minFee;
    uint256 maxFee;
}

enum FeeMode {
    Default,
    Fixed,
    SingleTier
}

/// @title  Base Distributor
/// @author Clique (@Clique2046)
/// @author Alan (@alannotnerd)
abstract contract BaseDistributor is OwnableRoles {
    using FixedPointMathLib for uint256;

    // address signing the claims
    address public signer;
    // vault address
    address public vault;
    // token address
    address public token;
    // Whether the token is wrapped
    bool public isWrappedToken = false;
    // whether the airdrop is active
    bool public active = false;
    // whether the recipient is dynamic
    bool public dynamicRecipient = false;
    // start time of the active window
    uint256 public activeWindowStartTime = 0;
    // end time of the active window
    uint256 public activeWindowEndTime = type(uint256).max;

    mapping(bytes32 => mapping(bytes32 => ClaimInfo)) public claimed;
    mapping(bytes32 root => bytes32 configurationId) public configurationId;

    mapping(bytes32 root => FeeMode) public feeModes;
    mapping(bytes32 root => uint256) public fixedFees;
    mapping(bytes32 root => SingleTierFeeRate) public singleTierFeeRates;

    uint256 public constant PROJECT_ADMIN = _ROLE_0;

    // errors
    error InvalidFeeConfig();
    error AlreadyClaimed();
    error InvalidSignature();
    error NotActive();
    error ZeroAddress();
    error InvalidMerkleProof(bytes32 root);
    error WithdrawFailed();
    error InvalidReleasedAmount();
    error IncorrectFee();
    error HandlerMismatch(bytes32 handler, address onBehalfOf);

    event AirdropClaimed(address indexed account, bytes32 indexed root, uint256 amount);
    event MerkleConfigurationUpdated(bytes32 indexed root, bytes32 indexed configurator);
    event Withdrawn(address indexed to, uint256 amount);
    event DefaultFeeApplied(bytes32 indexed root);
    event FixedFeeSet(bytes32 indexed root, uint256 fee);
    event SingleTierFeeRateSet(bytes32 indexed root, uint256 feeRate, uint256 minFee, uint256 maxFee);
    event VaultSet(address indexed vault);
    event TokenSet(address indexed token);
    event Paused();
    event Unpaused();
    event ActiveWindowSet(uint256 startTime, uint256 endTime);

    function version() external pure virtual returns (string memory) {
        return "3.0.0";
    }

    /// @notice Construct a new Claim contract
    /// @param _signer address that can sign messages
    /// @param _projectAdmin address that can set the signer and claim root
    constructor(
        address _signer,
        address _projectAdmin,
        address _vault,
        address _token,
        bool _dynamicRecipient,
        bool _isWrappedToken
    ) {
        if (_signer == address(0)) revert ZeroAddress();
        signer = _signer;
        vault = _vault;
        token = _token;
        dynamicRecipient = _dynamicRecipient;
        isWrappedToken = _isWrappedToken;
        _initializeOwner(msg.sender);
        _setRoles(_projectAdmin, PROJECT_ADMIN);
    }

    /// @notice Modifier to check if the airdrop is active
    /// forge-lint: disable-next-item(unwrapped-modifier-logic)
    modifier whenActive() {
        if (!active) revert NotActive();
        if (block.timestamp < activeWindowStartTime || block.timestamp > activeWindowEndTime) revert NotActive();
        _;
    }

    function requiredFee(bytes32 _root, uint256 _amount) public view returns (uint256) {
        FeeMode feeMode_ = feeModes[_root];

        if (feeMode_ == FeeMode.Default) {
            // use default fee mode
            return _resolveFee(bytes32(0), _amount);
        }

        return _resolveFee(_root, _amount);
    }

    /*´:°•.°+.*•´.*:˚.°*.˚•´.°:°•.°•.*•´.*:˚.°*.˚•´.°:°•.°+.*•´.*:*/
    /*                      ADMIN FUNCTIONS                       */
    /*.•°:°.´+˚.*°.˚:*.´•*.+°.•°:´*.´•*.•°.•°:°.´:•˚°.*°.˚:*.´+°.•*/

    /// @notice Set the signer
    /// @param _signer address that can sign messages
    function setSigner(address _signer) external onlyRoles(PROJECT_ADMIN) {
        signer = _signer;
    }

    /// @notice Set the claim root
    /// @param _claimRoot root of the merkle tree
    /// @param _configurationId configuration id
    function setClaimRoot(bytes32 _claimRoot, bytes32 _configurationId) external onlyRoles(PROJECT_ADMIN) {
        configurationId[_claimRoot] = _configurationId;
        emit MerkleConfigurationUpdated(_claimRoot, _configurationId);
    }

    /// @notice Set the vault
    /// @param _vault address of the vault
    function setVault(address _vault) external onlyRoles(PROJECT_ADMIN) {
        vault = _vault;
        emit VaultSet(_vault);
    }

    /// @notice Set the token
    /// @param _token address of the token
    function setToken(address _token) external onlyRoles(PROJECT_ADMIN) {
        token = _token;
        emit TokenSet(_token);
    }

    /// @notice Pause the airdrop
    function pause() external onlyRoles(PROJECT_ADMIN) {
        active = false;
        emit Paused();
    }

    /// @notice Unpause the airdrop
    function unpause() external onlyRoles(PROJECT_ADMIN) {
        active = true;
        emit Unpaused();
    }

    function setActiveWindow(uint256 _startTime, uint256 _endTime) external onlyRoles(PROJECT_ADMIN) {
        activeWindowStartTime = _startTime;
        activeWindowEndTime = _endTime;
        emit ActiveWindowSet(_startTime, _endTime);
    }

    function setDefault(bytes32 _root) external onlyRoles(PROJECT_ADMIN) {
        // Default fee cannot be default
        if (_root == bytes32(0)) {
            revert InvalidFeeConfig();
        }
        feeModes[_root] = FeeMode.Default;
        emit DefaultFeeApplied(_root);
    }

    /// @notice Set the fixed fee, and set fee mode to Fixed.
    /// @param _fee fee to set
    function setFixedFee(bytes32 _root, uint256 _fee) external onlyRoles(PROJECT_ADMIN) {
        feeModes[_root] = FeeMode.Fixed;
        fixedFees[_root] = _fee;
        emit FixedFeeSet(_root, _fee);
    }

    /// @notice Set the single tier fee rate, and set fee mode to SingleTier.
    function setSingleTierFeeRate(bytes32 _root, uint256 _feeRate, uint256 _minFee, uint256 _maxFee)
        external
        onlyRoles(PROJECT_ADMIN)
    {
        if (_minFee > _maxFee) revert InvalidFeeConfig();

        feeModes[_root] = FeeMode.SingleTier;
        singleTierFeeRates[_root] = SingleTierFeeRate({feeRate: _feeRate, minFee: _minFee, maxFee: _maxFee});
        emit SingleTierFeeRateSet(_root, _feeRate, _minFee, _maxFee);
    }

    /// @notice Set the dynamic recipient
    /// @param _dynamicRecipient whether the recipient is dynamic
    function setDynamicRecipient(bool _dynamicRecipient) external onlyRoles(PROJECT_ADMIN) {
        dynamicRecipient = _dynamicRecipient;
    }

    /// @notice Set the wrapped token
    /// @param _isWrappedToken whether the token is wrapped
    function setIsWrappedToken(bool _isWrappedToken) external onlyRoles(PROJECT_ADMIN) {
        isWrappedToken = _isWrappedToken;
    }

    /*´:°•.°+.*•´.*:˚.°*.˚•´.°:°•.°•.*•´.*:˚.°*.˚•´.°:°•.°+.*•´.*:*/
    /*                      FEE FUNCTIONS                         */
    /*.•°:°.´+˚.*°.˚:*.´•*.+°.•°:´*.´•*.•°.•°:°.´:•˚°.*°.˚:*.´+°.•*/
    /// @notice Withdraw the fee
    /// @dev Only callable by the owner
    function withdrawFee(address _recipient) external onlyOwner {
        uint256 _balance = address(this).balance;
        if (_balance > 0) {
            (bool _success,) = payable(_recipient).call{value: _balance}("");
            if (!_success) revert WithdrawFailed();
            emit Withdrawn(_recipient, _balance);
        }
    }

    /*´:°•.°+.*•´.*:˚.°*.˚•´.°:°•.°•.*•´.*:˚.°*.˚•´.°:°•.°+.*•´.*:*/
    /*                   EXTERNAL FUNCTIONS                       */
    /*.•°:°.´+˚.*°.˚:*.´•*.+°.•°:´*.´•*.•°.•°:°.´:•˚°.*°.˚:*.´+°.•*/

    /// @notice Claim airdrop tokens. Checks for both merkle proof
    //          and signature validation
    /// @param _proof merkle proof of the claim
    /// @param _signature signature of the claim
    /// @param _amount amount of tokens to claim
    /// @param _released amount of tokens that released
    /// @param _handler unique handler of recipient
    /// @param _onBehalfOf address to claim on behalf of
    /// @param _extra extra data to pass to the claim function
    function claim(
        bytes32[] calldata _proof,
        bytes calldata _signature,
        uint256 _amount,
        uint256 _released,
        bytes32 _handler,
        address _onBehalfOf,
        bytes calldata _extra
    ) external payable whenActive {
        if (!dynamicRecipient) {
            if (_handler != keccak256(abi.encodePacked(_onBehalfOf))) {
                revert HandlerMismatch(_handler, _onBehalfOf);
            }
        }

        (bytes32 _root,) = _rootCheck(_proof, _amount, _handler);

        ClaimInfo memory _claimInfo = claimed[_root][_handler];
        uint256 claimedAmount_ = _claimInfo.claimedAmount;

        // Only requires fee for the first claim
        if (claimedAmount_ == 0) {
            uint256 fee_ = requiredFee(_root, _amount);
            if (msg.value != fee_) {
                revert IncorrectFee();
            }
        }

        if (_amount < _released) {
            revert InvalidReleasedAmount();
        }

        if (claimedAmount_ == _released) {
            revert AlreadyClaimed();
        }

        claimed[_root][_handler] = ClaimInfo({lastClaimedBlock: block.number, claimedAmount: _released});

        _signatureCheck(_amount, _released, _handler, _onBehalfOf, _signature, _root, signer, _extra);

        uint256 _claimableAmount = _released - claimedAmount_;

        _execute(vault, _onBehalfOf, _root, _claimableAmount, _extra);
        emit AirdropClaimed(_onBehalfOf, _root, _claimableAmount);
    }

    /*´:°•.°+.*•´.*:˚.°*.˚•´.°:°•.°•.*•´.*:˚.°*.˚•´.°:°•.°+.*•´.*:*/
    /*                       PRIVATE FUNCTIONS                    */
    /*.•°:°.´+˚.*°.˚:*.´•*.+°.•°:´*.´•*.•°.•°:°.´:•˚°.*°.˚:*.´+°.•*/

    /// @notice Internal function to execute the claim
    /// @param _vault vault address
    /// @param _recipient recipient address
    /// @param _root root of the merkle tree
    /// @param _amount amount of tokens to claim
    /// @param _extra extra data to pass to the claim function
    function _execute(address _vault, address _recipient, bytes32 _root, uint256 _amount, bytes memory _extra)
        internal
        virtual;

    /// @notice Internal function to check the merkle proof
    /// @param _proof merkle proof of the claim
    /// @param _amount amount of tokens to claim
    /// @param _handler unique handler of recipient
    function _rootCheck(bytes32[] calldata _proof, uint256 _amount, bytes32 _handler)
        internal
        view
        returns (bytes32 root, bytes32 _configurationId)
    {
        root = recover(_proof, keccak256(abi.encodePacked(_handler, _amount)));
        _configurationId = configurationId[root];
        if (_configurationId == bytes32(0)) revert InvalidMerkleProof(root);
    }

    /// @notice Internal function to check the signature
    /// @param _amount amount of tokens to claim
    /// @param _released amount of tokens that released
    /// @param _handler unique handler of recipient
    /// @param _onBehalfOf address to claim on behalf of
    /// @param _signature signature of the claim
    /// @param _root root of the merkle tree
    /// @param _signer signer to check
    function _signatureCheck(
        uint256 _amount,
        uint256 _released,
        bytes32 _handler,
        address _onBehalfOf,
        bytes calldata _signature,
        bytes32 _root,
        address _signer,
        bytes calldata _extra
    ) internal view {
        if (_signature.length == 0) revert InvalidSignature();

        /// forge-lint: disable-next-item(asm-keccak256)
        bytes32 messageHash = keccak256(
            abi.encodePacked(_handler, _onBehalfOf, _amount, _released, _root, address(this), block.chainid, _extra)
        );
        bytes32 prefixedHash = ECDSA.toEthSignedMessageHash(messageHash);
        address recoveredSigner = ECDSA.recoverCalldata(prefixedHash, _signature);

        if (recoveredSigner != _signer) revert InvalidSignature();
    }

    /// @notice Internal function to resolve the fee
    /// @param _root root of the merkle tree
    /// @param _amount amount of tokens to claim
    function _resolveFee(bytes32 _root, uint256 _amount) internal view returns (uint256) {
        FeeMode feeMode_ = feeModes[_root];
        // Here we simulate a switch-case statement, and we intentionally still
        // use an "if" with the last enum variant.

        if (feeMode_ == FeeMode.Fixed) {
            return fixedFees[_root];
        }

        if (feeMode_ == FeeMode.SingleTier) {
            SingleTierFeeRate memory feeRate_ = singleTierFeeRates[_root];
            uint256 fee_ = _amount.mulWadUp(feeRate_.feeRate);
            if (fee_ <= feeRate_.minFee) {
                return feeRate_.minFee;
            }
            if (fee_ >= feeRate_.maxFee) {
                return feeRate_.maxFee;
            }
            return fee_;
        }

        // Should be unreachable
        revert InvalidFeeConfig();
    }

    /*´:°•.°+.*•´.*:˚.°*.˚•´.°:°•.°•.*•´.*:˚.°*.˚•´.°:°•.°+.*•´.*:*/
    /*            MERKLE PROOF VERIFICATION OPERATIONS            */
    /*.•°:°.´+˚.*°.˚:*.´•*.+°.•°:´*.´•*.•°.•°:°.´:•˚°.*°.˚:*.´+°.•*/

    /// @dev Returns whether `leaf` exists in the Merkle tree with `root`, given `proof`.
    function recover(bytes32[] memory proof, bytes32 leaf) internal pure returns (bytes32 root) {
        /// @solidity memory-safe-assembly
        assembly {
            if mload(proof) {
                // Initialize `offset` to the offset of `proof` elements in memory.
                let offset := add(proof, 0x20)
                // Left shift by 5 is equivalent to multiplying by 0x20.
                let end := add(offset, shl(5, mload(proof)))
                // Iterate over proof elements to compute root hash.
                for {} 1 {} {
                    // Slot of `leaf` in scratch space.
                    // If the condition is true: 0x20, otherwise: 0x00.
                    let scratch := shl(5, gt(leaf, mload(offset)))
                    // Store elements to hash contiguously in scratch space.
                    // Scratch space is 64 bytes (0x00 - 0x3f) and both elements are 32 bytes.
                    mstore(scratch, leaf)
                    mstore(xor(scratch, 0x20), mload(offset))
                    // Reuse `leaf` to store the hash to reduce stack operations.
                    leaf := keccak256(0x00, 0x40)
